    int load_y = yidx;

    if (load_x < 0) load_x = 0;
    if (load_x > grid_cols - 1) load_x = grid_cols - 1;
    if (load_y < 0) load_y = 0;
    if (load_y > grid_rows - 1) load_y = grid_rows - 1;

