	k02 = k20/Kd02;
	k42 = 500;
	k24 = k42/Kd24;

	k0Boff = 0.0014f;
	k0Bon = k0Boff/0.2f;
	k2Boff = k0Boff/100.0f;
	k2Bon = k0Bon;
	k4Boff = k2Boff;
	k4Bon = k0Bon;

	k20B = k20/100.0f;
	k02B = k02;
	k42B = k42;
	k24B = k24;

	kbi = 2.2f;
	kib = kbi/33.5e-3f;
	kpp1 = 1.72f;
	Kmpp1 = 11.5f;
	kib2 = kib;
	kb2i = kib2*5;
	kb24 = k24;
	kb42 = k42*33.5e-3f/5;
	kta = kbi/1000.0f;
	kat = kib;
	kt42 = k42*33.5e-6f/5;
	kt24 = k24;
	kat2 = kib;
	kt2a = kib*5;

	kcanCaoff = 1;
	kcanCaon = kcanCaoff/0.5f;
	kcanCaM4on = 46;
	kcanCaM4off = 0.0013f;
	kcanCaM2on = kcanCaM4on;
	kcanCaM2off = 2508*kcanCaM4off;
