inline ulong LCG_random_int(ulong *seed){
  const ulong a = 2806196910506780709UL;
  const ulong c = 1UL;
  const ulong mask = 0x7fffffffffffffffUL; // m = 2^63
  *seed = (a * (*seed) + c) & mask;
  return *seed;
}

inline double LCG_random_double(ulong *seed){
  const double m = 9223372036854775808.0;
  ulong x = LCG_random_int(seed);
  return (double)x / m;
}

inline ulong fast_forward_LCG(ulong seed, ulong n){
  const ulong mask = 0x7fffffffffffffffUL; // m = 2^63
  ulong a = 2806196910506780709UL;
  ulong c = 1UL;

  n &= mask;

  ulong a_new = 1UL;
  ulong c_new = 0UL;

  while (n > 0UL){
    if (n & 1UL){
      a_new *= a;
      c_new = c_new * a + c;
    }
    c *= (a + 1UL);
    a *= a;
    n >>= 1UL;
  }
  return (a_new * seed + c_new) & mask;
}

inline int pick_mat(ulong *seed){
  double dist[12] = {
    0.140, 0.052, 0.275, 0.134, 0.154, 0.064,
    0.066, 0.055, 0.008, 0.015, 0.025, 0.013
  };

  double roll = LCG_random_double(seed);

  for (int i = 0; i < 12; i++){
    double running = 0.0;
    for (int j = i; j > 0; j--)
      running += dist[j];
    if (roll < running)
      return i;
  }
  return 0;
}

inline void calculate_sig_T(int nuc, double E, Input input, __global const double *pseudo_K0RS, RSComplex *sigTfactors){
  for (int i = 0; i < 4; i++){
    double phi = pseudo_K0RS[nuc * input.numL + i] * sqrt(E);

    if (i == 1)
      phi -= -atan(phi);
    else if (i == 2)
      phi -= atan(3.0 * phi / (3.0 - phi * phi));
    else if (i == 3)
      phi -= atan(phi * (15.0 - phi * phi) / (15.0 - 6.0 * phi * phi));

    phi *= 2.0;
    sigTfactors[i].r = cos(phi);
    sigTfactors[i].i = -sin(phi);
  }
}

inline void calculate_micro_xs(
  double *micro_xs, int nuc, double E, Input input,
  __global const int *n_windows,
  __global const double *pseudo_K0RS,
  __global const Window *windows,
  __global const Pole *poles,
  int max_num_windows, int max_num_poles)
{
  double sigT, sigA, sigF, sigE;

  double spacing = 1.0 / (double)n_windows[nuc];
  int window = (int)(E / spacing);
  if (window == n_windows[nuc]) window--;

  RSComplex sigTfactors[4];
  calculate_sig_T(nuc, E, input, pseudo_K0RS, sigTfactors);

  Window w = windows[nuc * max_num_windows + window];
  sigT = E * w.T;
  sigA = E * w.A;
  sigF = E * w.F;

  for (int i = w.start; i < w.end; i++){
    Pole pole = poles[nuc * max_num_poles + i];
    RSComplex t1 = {0.0, 1.0};
    RSComplex t2 = {sqrt(E), 0.0};
    RSComplex PSIIKI = c_div(t1, c_sub(pole.MP_EA, t2));
    RSComplex E_c = {E, 0.0};
    RSComplex CDUM = c_div(PSIIKI, E_c);
    sigT += c_mul(pole.MP_RT, c_mul(CDUM, sigTfactors[pole.l_value])).r;
    sigA += c_mul(pole.MP_RA, CDUM).r;
    sigF += c_mul(pole.MP_RF, CDUM).r;
  }

  sigE = sigT - sigA;
  micro_xs[0] = sigT; micro_xs[1] = sigA; micro_xs[2] = sigF; micro_xs[3] = sigE;
}

inline void calculate_micro_xs_doppler(
  double *micro_xs, int nuc, double E, Input input,
  __global const int *n_windows,
  __global const double *pseudo_K0RS,
  __global const Window *windows,
  __global const Pole *poles,
  int max_num_windows, int max_num_poles)
{
  double sigT, sigA, sigF, sigE;

  double spacing = 1.0 / (double)n_windows[nuc];
  int window = (int)(E / spacing);
  if (window == n_windows[nuc]) window--;

  RSComplex sigTfactors[4];
  calculate_sig_T(nuc, E, input, pseudo_K0RS, sigTfactors);

  Window w = windows[nuc * max_num_windows + window];
  sigT = E * w.T;
  sigA = E * w.A;
  sigF = E * w.F;

  double dopp = 0.5;

  for (int i = w.start; i < w.end; i++){
    Pole pole = poles[nuc * max_num_poles + i];
    RSComplex E_c = {E, 0.0};
    RSComplex dopp_c = {dopp, 0.0};
    RSComplex Z = c_mul(c_sub(E_c, pole.MP_EA), dopp_c);
    RSComplex faddeeva = fast_nuclear_W(Z);

    sigT += c_mul(pole.MP_RT, c_mul(faddeeva, sigTfactors[pole.l_value])).r;
    sigA += c_mul(pole.MP_RA, faddeeva).r;
    sigF += c_mul(pole.MP_RF, faddeeva).r;
  }

  sigE = sigT - sigA;
  micro_xs[0] = sigT; micro_xs[1] = sigA; micro_xs[2] = sigF; micro_xs[3] = sigE;
}

inline void calculate_macro_xs(
  double *macro_xs, int mat, double E, Input input,
  __global const int *num_nucs,
  __global const int *mats,
  int max_num_nucs,
  __global const double *concs,
  __global const int *n_windows,
  __global const double *pseudo_K0RS,
  __global const Window *windows,
  __global const Pole *poles,
  int max_num_windows, int max_num_poles)
{
  for (int i = 0; i < 4; i++) macro_xs[i] = 0.0;

  for (int i = 0; i < num_nucs[mat]; i++){
    double micro_xs[4];
    int nuc = mats[mat * max_num_nucs + i];

    if (input.doppler == 1)
      calculate_micro_xs_doppler(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);
    else
      calculate_micro_xs(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

    double c = concs[mat * max_num_nucs + i];
    for (int j = 0; j < 4; j++) macro_xs[j] += micro_xs[j] * c;
  }
}

__kernel void macro_xs_lookup_kernel(
  Input input,
  __global const int *num_nucs,
  __global const int *mats,
  int max_num_nucs,
  __global const double *concs,
  __global const int *n_windows,
  __global const double *pseudo_K0RS,
  __global const Window *windows,
  __global const Pole *poles,
  int max_num_windows,
  int max_num_poles,
  __global int *verification_array)
{
  int i = get_global_id(0);
  if (i >= input.lookups) return;

  ulong seed = STARTING_SEED;
  seed = fast_forward_LCG(seed, (ulong)(2 * i));

  double E = LCG_random_double(&seed);
  int mat = pick_mat(&seed);

  double macro_xs[4];
  calculate_macro_xs(macro_xs, mat, E, input, num_nucs, mats, max_num_nucs, concs,
                     n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

  double maxv = -1.7976931348623157e308;
  int max_idx = 0;
  for (int x = 0; x < 4; x++){
    if (macro_xs[x] > maxv){
      maxv = macro_xs[x];
      max_idx = x;
    }
  }
  verification_array[i] = max_idx + 1;
}

