inline RSComplex c_add(RSComplex A, RSComplex B)
{
  RSComplex C;
  C.r = A.r + B.r;
  C.i = A.i + B.i;
  return C;
}

inline RSComplex c_sub(RSComplex A, RSComplex B)
{
  RSComplex C;
  C.r = A.r - B.r;
  C.i = A.i - B.i;
  return C;
}

inline RSComplex c_mul(RSComplex A, RSComplex B)
{
  RSComplex C;
  C.r = (A.r * B.r) - (A.i * B.i);
  C.i = (A.r * B.i) + (A.i * B.r);
  return C;
}

inline RSComplex c_div(RSComplex A, RSComplex B)
{
  RSComplex C;
  double denom = B.r * B.r + B.i * B.i;
  C.r = ((A.r * B.r) + (A.i * B.i)) / denom;
  C.i = ((A.i * B.r) - (A.r * B.i)) / denom;
  return C;
}

inline double c_abs(RSComplex A)
{
  return sqrt(A.r * A.r + A.i * A.i);
}

inline double fast_exp(double x)
{
  x = 1.0 + x * 0.000244140625;
  x *= x; x *= x; x *= x; x *= x;
  x *= x; x *= x; x *= x; x *= x;
  x *= x; x *= x; x *= x; x *= x;
  return x;
}

inline RSComplex fast_cexp(RSComplex z)
{
  double t1 = fast_exp(z.r);
  RSComplex t4 = { cos(z.i), sin(z.i) };
  RSComplex t5 = { t1, 0.0 };
  return c_mul(t5, t4);
}

inline RSComplex fast_nuclear_W(RSComplex Z)
{
  if (c_abs(Z) < 6.0)
  {
