      3.553058e+02, 4.836106e+02, 6.316547e+02, 7.994380e+02, 9.869604e+02
    };

    RSComplex t1 = {0.0, 12.0};
    RSComplex t2 = {12.0, 0.0};
    RSComplex i  = {0.0, 1.0};
    RSComplex one = {1.0, 0.0};

    RSComplex W = c_div(c_mul(i, c_sub(one, fast_cexp(c_mul(t1, Z)))), c_mul(t2, Z));
    RSComplex sum = {0.0, 0.0};

    for (int n = 0; n < 10; n++)
    {
      RSComplex t3 = {neg_1n[n], 0.0};
      RSComplex top = c_sub(c_mul(t3, fast_cexp(c_mul(t1, Z))), one);
      RSComplex t4 = {denominator_left[n], 0.0};
      RSComplex t5 = {144.0, 0.0};
      RSComplex bot = c_sub(t4, c_mul(t5, c_mul(Z, Z)));
      RSComplex t6 = {an[n], 0.0};
      sum = c_add(sum, c_mul(t6, c_div(top, bot)));
    }
    W = c_add(W, c_mul(prefactor, c_mul(Z, sum)));
    return W;
  }
  else
  {
    RSComplex a = {0.512424224754768462984202823134979415014943561548661637413182, 0.0};
    RSComplex b = {0.275255128608410950901357962647054304017026259671664935783653, 0.0};
