		num_nucs, mats, max_num_nucs, concs,
		n_windows, pseudo_K0RS, windows, poles,
		max_num_windows, max_num_poles);

	double maxv = -1.7976931348623158e308;
	int max_idx = 0;
	for (int x = 0; x < 4; x++)
	{
		if (maxv < macro_xs[x])
		{
			maxv = macro_xs[x];
			max_idx = x;
		}
	}

	verification_array[i] = max_idx + 1;
}

