inline double LCG_random_double(ulong *seed)
{
	const ulong m = 9223372036854775808UL;
	const ulong a = 2806196910506780709UL;
	const ulong c = 1UL;
	*seed = (a * (*seed) + c) % m;
	return (double)(*seed) / (double)m;
}

inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong m = 9223372036854775808UL;
	ulong a = 2806196910506780709UL;
	ulong c = 1UL;

	n = n % m;

	ulong a_new = 1UL;
	ulong c_new = 0UL;

	while (n > 0)
	{
		if (n & 1UL)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1UL);
		a *= a;
		n >>= 1;
	}

	return (a_new * seed + c_new) % m;
}

inline int pick_mat(ulong *seed)
{
	const double dist0  = 0.140;
	const double dist1  = 0.052;
	const double dist2  = 0.275;
	const double dist3  = 0.134;
	const double dist4  = 0.154;
	const double dist5  = 0.064;
	const double dist6  = 0.066;
	const double dist7  = 0.055;
	const double dist8  = 0.008;
	const double dist9  = 0.015;
	const double dist10 = 0.025;
	const double dist11 = 0.013;

	double roll = LCG_random_double(seed);

	double running = 0.0;
	running += dist1 + dist2 + dist3 + dist4 + dist5 + dist6 + dist7 + dist8 + dist9 + dist10 + dist11;
	if (roll < running) return 0;
	running -= dist1;
	if (roll < running) return 1;
	running -= dist2;
	if (roll < running) return 2;
	running -= dist3;
	if (roll < running) return 3;
	running -= dist4;
	if (roll < running) return 4;
	running -= dist5;
	if (roll < running) return 5;
	running -= dist6;
	if (roll < running) return 6;
	running -= dist7;
	if (roll < running) return 7;
	running -= dist8;
	if (roll < running) return 8;
	running -= dist9;
	if (roll < running) return 9;
	running -= dist10;
	if (roll < running) return 10;
	running -= dist11;
	if (roll < running) return 11;

	return 0;
}

inline void calculate_micro_xs(
	double p_energy, int nuc, long n_isotopes, long n_gridpoints,
	__global double *egrid, __global int *index_data, __global NuclideGridPoint *nuclide_grids,
	long idx, double *xs_vector, int grid_type, int hash_bins)
{
	double f;
	__global NuclideGridPoint *low;
	__global NuclideGridPoint *high;

	if (grid_type == NUCLIDE)
	{
		idx = grid_search_nuclide(n_gridpoints, p_energy, &nuclide_grids[(long)nuc * n_gridpoints], 0, n_gridpoints - 1);
		if (idx == n_gridpoints - 1)
			low = &nuclide_grids[(long)nuc * n_gridpoints + idx - 1];
		else
			low = &nuclide_grids[(long)nuc * n_gridpoints + idx];
	}
	else if (grid_type == UNIONIZED)
	{
		long index = index_data[idx * n_isotopes + nuc];
		if (index == n_gridpoints - 1)
			low = &nuclide_grids[(long)nuc * n_gridpoints + index - 1];
		else
			low = &nuclide_grids[(long)nuc * n_gridpoints + index];
	}
	else
	{
		int u_low = index_data[idx * n_isotopes + nuc];
		int u_high;
		if (idx == hash_bins - 1)
			u_high = (int)(n_gridpoints - 1);
		else
			u_high = index_data[(idx + 1) * n_isotopes + nuc] + 1;

		double e_low = nuclide_grids[(long)nuc * n_gridpoints + u_low].energy;
		double e_high = nuclide_grids[(long)nuc * n_gridpoints + u_high].energy;
		int lower;
		if (p_energy <= e_low)
			lower = 0;
		else if (p_energy >= e_high)
			lower = (int)(n_gridpoints - 1);
		else
			lower = (int)grid_search_nuclide(n_gridpoints, p_energy, &nuclide_grids[(long)nuc * n_gridpoints], u_low, u_high);

		if (lower == n_gridpoints - 1)
			low = &nuclide_grids[(long)nuc * n_gridpoints + lower - 1];
		else
			low = &nuclide_grids[(long)nuc * n_gridpoints + lower];
	}

	high = low + 1;
	f = (high->energy - p_energy) / (high->energy - low->energy);

	xs_vector[0] = high->total_xs      - f * (high->total_xs      - low->total_xs);
	xs_vector[1] = high->elastic_xs    - f * (high->elastic_xs    - low->elastic_xs);
	xs_vector[2] = high->absorbtion_xs - f * (high->absorbtion_xs - low->absorbtion_xs);
	xs_vector[3] = high->fission_xs    - f * (high->fission_xs    - low->fission_xs);
	xs_vector[4] = high->nu_fission_xs - f * (high->nu_fission_xs - low->nu_fission_xs);
}

inline void calculate_macro_xs(
	double p_energy, int mat, long n_isotopes, long n_gridpoints,
	__global int *num_nucs, __global double *concs, __global double *egrid,
	__global int *index_data, __global NuclideGridPoint *nuclide_grids,
	__global int *mats, double *macro_xs_vector, int grid_type, int hash_bins, int max_num_nucs)
{
	int p_nuc;
	long idx = -1;
	double conc;

	for (int k = 0; k < 5; k++)
		macro_xs_vector[k] = 0.0;

	if (grid_type == UNIONIZED)
		idx = grid_search(n_isotopes * n_gridpoints, p_energy, egrid);
	else if (grid_type == HASH)
	{
		double du = 1.0 / (double)hash_bins;
		idx = (long)(p_energy / du);
	}

	for (int j = 0; j < num_nucs[mat]; j++)
	{
		double xs_vector[5];
		p_nuc = mats[mat * max_num_nucs + j];
		conc = concs[mat * max_num_nucs + j];

		calculate_micro_xs(p_energy, p_nuc, n_isotopes, n_gridpoints, egrid, index_data,
		                   nuclide_grids, idx, xs_vector, grid_type, hash_bins);

		for (int k = 0; k < 5; k++)
			macro_xs_vector[k] += xs_vector[k] * conc;
	}
}

__kernel void macro_xs_lookup_kernel(
	Inputs in,
